class Solution:
    def countSubarrays(self, nums, k):
        max_val = max(nums)
        n = len(nums)
        total = 0
        for i in range(n):
            count = 0
            for j in range(i, n):
                if nums[j] == max_val:
                    count += 1
                if count >= k:
                    total += 1
        return total

