class Solution:
    def countSubarrays(self, nums, k):
        max_val = max(nums)
        left = 0
        count_max = 0
        ans = 0
        for right in range(len(nums)):
            if nums[right] == max_val:
                count_max += 1
            while count_max >= k:
                if nums[left] == max_val:
                    count_max -= 1
                left += 1
            ans += left
        return ans

