var countSubarrays = function(nums, k) {
    let maxVal = -Infinity;
    for (const v of nums) {
        if (v > maxVal) maxVal = v;
    }
    let left = 0;
    let countMax = 0;
    let ans = 0;
    for (let right = 0; right < nums.length; right++) {
        if (nums[right] === maxVal) countMax++;
        while (countMax >= k) {
            if (nums[left] === maxVal) countMax--;
            left++;
        }
        ans += left;
    }
    return ans;
};
